begin;

create table public.world_country_registry(
  code text primary key check(code ~ '^[A-Z]{2}$'),
  canonical_name text not null unique,
  region text,
  subregion text,
  aliases jsonb not null default '[]'::jsonb,
  supported_languages text[] not null default '{}',
  currency_code text check(currency_code is null or currency_code ~ '^[A-Z]{3}$'),
  provenance jsonb not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.world_country_registry enable row level security;
create policy world_country_registry_read on public.world_country_registry
  for select to authenticated using(true);

on conflict(code) do update set canonical_name=excluded.canonical_name,provenance=excluded.provenance,updated_at=now();

comment on table public.world_country_registry is 'Canonical ISO 3166-1 country and territory identities. Null intelligence fields mean unavailable, never inferred.';

commit;

